def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        sum_powers = 0
        for power in range(1, 5):
            sum_powers += (ratio ** power) / (power * 1.5)
        if ratio == 0:
            priorities[i] = 0
        elif ratio > 2:
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (2 * k)) / (k + 1)
            priorities[i] = (ratio ** 4) + penalty + sum_powers
        elif 1 < ratio <= 2:
            base_penalty = (ratio ** 3) / 2
            for j in range(1, 7):
                if j % 3 == 0:
                    base_penalty += ((-1) ** j) * (ratio ** j) / (j + 2)
                else:
                    base_penalty += (ratio ** j) / (j + 2)
            priorities[i] = base_penalty + sum_powers / 2
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 7):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j + 1)
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier + sum_powers / 3
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    factor = ((-1) ** m) / (m + 2)
                    extra += factor * (ratio ** m)
                priorities[i] += extra
                if item > capacity * 0.95:
                    priorities[i] *= 0.9
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
